mapper.select:
SELECT ,
       pst.tag_id, pst.tag_name, pst.tag_color, pst.order_num, pst.status AS tag_status
FROM plan_scheme ps
LEFT JOIN plan_scheme_tag_rel pstr ON ps.scheme_id = pstr.scheme_id
LEFT JOIN plan_scheme_tag pst ON pstr.tag_id = pst.tag_id
WHERE ps.del_flag = '0'

    AND ps.scheme_code LIKE CONCAT('%', #{schemeCode}, '%')


    AND ps.scheme_name LIKE CONCAT('%', #{schemeName}, '%')


    AND ps.scheme_type = #{schemeType}


    AND ps.scheme_status = #{schemeStatus}


    AND ps.plan_year = #{planYear}


    AND ps.lead_dept_id = #{leadDeptId}

ORDER BY ps.create_time DESC, ps.scheme_id DESC

mapper.insert:
