    scheme_code, scheme_name, scheme_type, plan_year, lead_dept_id, lead_dept_name,
    leader_id, leader_name, total_amount, scheme_status, version_no, process_instance_id,
    attachments, del_flag, create_by, create_time, remark
) VALUES (
    #{schemeCode}, #{schemeName}, #{schemeType}, #{planYear}, #{leadDeptId}, #{leadDeptName},
    #{leaderId}, #{leaderName}, #{totalAmount}, #{schemeStatus}, #{versionNo}, #{processInstanceId},
    #{attachments}, #{delFlag}, #{createBy}, #{createTime}, #{remark}
)
